The code mentioned above is too complex to understand, because it is trying to add synchronization on queues and visited sets, which is not required. Also, no need to have countDown latch to track and shutdown workers. We can simply iterate through submitted futures and wait for it to complete.

public int crawl(String seedUrl, int maxThrads, Map<String, List<String>> urlMap) {
        ExecutorService threadPool = Executors.newFixedThreadPool(maxThrads);
        Queue<String> queue = new LinkedList<>();
        Set<String> visited = new HashSet<>();
        queue.add(seedUrl);
        String domain = getDomain(seedUrl);
        List<Future<Void>> tasks = new LinkedList<>();

        while (!queue.isEmpty()) {
            String url = queue.poll();
            visited.add(url);
            tasks.add(threadPool.submit(() -> {
                return crawl(url);
            }));
            urlMap.getOrDefault(url, Collections.emptyList())
                .stream()
                .filter(adjUrl -> !visited.contains(adjUrl))
                .filter(adjUrl -> getDomain(adjUrl).equals(domain))
                .forEach(queue::add);
        }

        tasks.forEach(future -> {
            try {
                future.get();
            } catch(Exception e) {}
        });
        return visited.size();
    }

    private String getDomain(String url) {
        try {
            return new URL(url).getHost();
        } catch(Exception e) {
            throw new RuntimeException();
        }
    }

    private Void crawl(String url) {
        //crawl logic.
        return null;
    }

