Here is a true minimal really concurrent parser

def parse_domain(url):
    return urlparse(url).netloc

def crawl(g, seed_url, num_workers) -> List[str]:
    domain = parse_domain(seed_url)
    visited = set([seed_url])
    q = deque([seed_url])
    lock = Lock()
    url_avail_condition = Condition(lock)
    pending_urls = 1

    def worker():
        nonlocal pending_urls
        while True:
            with url_avail_condition:
                while pending_urls > 0 and not q:
                    url_avail_condition.wait()

                if pending_urls == 0 and not q:
                    return 

                url_to_process = q.popleft()

            links = [x for x in g.get(url_to_process, []) if parse_domain(x) == domain]

            with url_avail_condition:
                for link in links:
                    if link not in visited:
                        visited.add(link)
                        q.append(link)
                        pending_urls += 1
                        url_avail_condition.notify(1)

                pending_urls -= 1
                if pending_urls == 0:
                    url_avail_condition.notify_all()

    with ThreadPoolExecutor(num_workers) as pool:
        jobs = [pool.submit(worker) for _ in range(num_workers)]
        for job in jobs:
            job.result()

    return visited

